from openai import OpenAI
from typing import Literal
from pydantic import BaseModel,Field

class ClothingInfo(BaseModel):
    category: Literal["Dress","Coat","Shirt","Other"]=Field(description="")
    primary_color: str=Field()
    target_age_group: str



def analyze_clothing(image_url):
    client = OpenAI()
    response = client.chat.completions.parse(
    model="gpt-4.1-mini",
         messages=[
            {
                "role": "user",
                "content": [
                    {"type": "text", "text": "Analyze this clothing item and return details in JSON format."},
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": image_url
                        },
                    },
                ],
            }
        ],
    response_format=ClothingInfo
    )   
    return(response.choices[0].message.parsed)

print(analyze_clothing( "data:image/webp;base64,"))

    
